arguments.command:
# The source files don't exist - only the binlog. Let's write a C# program to parse the binlog in detail
# to extract project dependency information and all errors
mkdir -p /tmp/binlog-analyzer && cd /tmp/binlog-analyzer && cat > Program.cs << 'EOF'
using Microsoft.Build.Logging.StructuredLogger;
using System;
using System.Collections.Generic;
using System.Linq;

var binlogPath = "/tmp/sv-9f81bdcebf9d4e5a99861f2ee443bb8b/build.binlog";
var build = BinaryLog.ReadBuild(binlogPath);

Console.WriteLine("=== BUILD RESULT ===");
Console.WriteLine($"Succeeded: {build.Succeeded}");
Console.WriteLine();

// Get all projects
Console.WriteLine("=== PROJECTS ===");
var projects = build.FindChildrenRecursive<Project>().ToList();
foreach (var p in projects)
{
    Console.WriteLine($"  Project: {p.Name} | Succeeded: {p.Succeeded}");
}
Console.WriteLine();

// Get all errors
Console.WriteLine("=== ALL ERRORS ===");
var errors = build.FindChildrenRecursive<Error>().ToList();
foreach (var e in errors)
{
    Console.WriteLine($"  [{e.Code}] {e.File}({e.LineNumber},{e.ColumnNumber}): {e.Text}");
    if (e.GetNearestParent<Project>() is Project proj)
        Console.WriteLine($"    In project: {proj.Name}");
    Console.WriteLine();
}

// Get source files referenced in the build
Console.WriteLine("=== SOURCE FILES IN FAILED PROJECTS ===");
var items = build.FindChildrenRecursive<Item>().Where(i => i.Name == "Compile").ToList();
foreach (var item in items)
{
    var proj = item.GetNearestParent<Project>();
    if (proj != null && !proj.Succeeded)
        Console.WriteLine($"  {proj.Name}: {item.Text}");
}
Console.WriteLine();

// Look for PackageReference items
Console.WriteLine("=== PACKAGE REFERENCES ===");
var pkgRefs = build.FindChildrenRecursive<Item>().Where(i => i.Name == "PackageReference").ToList();
foreach (var item in pkgRefs)
{
    var proj = item.GetNearestParent<Project>();
    Console.WriteLine($"  {proj?.Name}: {item.Text}");
}
Console.WriteLine();

// Look for project references
Console.WriteLine("=== PROJECT REFERENCES ===");
var projRefs = build.FindChildrenRecursive<Item>().Where(i => i.Name == "ProjectReference").ToList();
foreach (var item in projRefs)
{
    var proj = item.GetNearestParent<Project>();
    Console.WriteLine($"  {proj?.Name} references -> {item.Text}");
}
EOF

