    Console.WriteLine($"  [{e.Code}] {e.File}({e.LineNumber},{e.ColumnNumber}): {e.Text}");
    if (e.GetNearestParent<Project>() is Project proj)
        Console.WriteLine($"    In project: {proj.Name}");
    Console.WriteLine();
}

// Get source files referenced in the build
Console.WriteLine("=== SOURCE FILES (Compile items) ===");
var items = build.FindChildrenRecursive<Item>().Where(i => i.Name == "Compile").ToList();
foreach (var item in items)
{
    var proj = item.GetNearestParent<Project>();
    Console.WriteLine($"  {proj?.Name}: {item.Text}");
}
Console.WriteLine();

// Look for PackageReference items
Console.WriteLine("=== PACKAGE REFERENCES ===");
