Console.WriteLine("=== SOLUTION BUILD TARGETS ===");
var slnProjects = build.FindChildrenRecursive<Project>().Where(p => p.Name == "BuildDiag.sln").ToList();
foreach (var sln in slnProjects)
{
    var targets = sln.FindChildrenRecursive<Target>().ToList();
    foreach (var t in targets.Where(t => !t.Succeeded))
    {
        Console.WriteLine($"  FAILED target: {t.Name}");
    }
}
EOF

