using Microsoft.Build.Logging.StructuredLogger;
using System;
using System.Collections.Generic;
using System.Linq;

var binlogPath = "/tmp/sv-9f81bdcebf9d4e5a99861f2ee443bb8b/build.binlog";
var build = BinaryLog.ReadBuild(binlogPath);

// Get the resolved package references from project.assets.json or restore targets
Console.WriteLine("=== RESOLVED PACKAGES (from AddItem) ===");
var allAddItems = build.FindChildrenRecursive<AddItem>().ToList();
var pkgItems = allAddItems.Where(a => a.Name.Contains("Package") && !a.Name.Contains("Path")).ToList();
foreach (var group in pkgItems.GroupBy(a => a.Name))
{
    Console.WriteLine($"\n  Item group: {group.Key}");
    foreach (var addItem in group.Take(10))
    {
        var proj = addItem.GetNearestParent<Project>();
        foreach (var child in addItem.Children.OfType<Item>().Take(5))
        {
            Console.WriteLine($"    {proj?.Name}: {child.Text}");
        }
    }
}
Console.WriteLine();

// Look specifically for NuGet restore output
Console.WriteLine("=== NUGET RESTORE INFO ===");
var restoreMsgs = build.FindChildrenRecursive<Message>()
    .Where(m => m.Text != null && (m.Text.Contains("Newtonsoft") || m.Text.Contains("Json")))
    .ToList();
foreach (var m in restoreMsgs.Take(20))
{
    Console.WriteLine($"  {m.Text}");
}
Console.WriteLine();

// Look at the Services.csproj properties
Console.WriteLine("=== SERVICES.CSPROJ PROPERTIES ===");
var svcProjects = build.FindChildrenRecursive<Project>().Where(p => p.Name == "Services.csproj").ToList();
foreach (var svc in svcProjects.Take(1))
{
    var props = svc.FindChildrenRecursive<Property>()
        .Where(p => p.Name.Contains("Package") || p.Name.Contains("Reference"))
        .Take(10).ToList();
    foreach (var p in props)
        Console.WriteLine($"  {p.Name} = {p.Value}");
}
Console.WriteLine();

// What packages were resolved for Services?
Console.WriteLine("=== NativeCommandLinePackageReference or PackageDownload for Services ===");
foreach (var addItem in allAddItems)
{
    var proj = addItem.GetNearestParent<Project>();
    if (proj?.Name == "Services.csproj")
    {
        foreach (var child in addItem.Children.OfType<Item>())
        {
            if (child.Text.Contains("Newtonsoft", StringComparison.OrdinalIgnoreCase) ||
                child.Text.Contains("Json", StringComparison.OrdinalIgnoreCase))
            {
                Console.WriteLine($"  {addItem.Name}: {child.Text}");
            }
        }
    }
}
EOF

