    if (cscTask != null)
    {
        // Get the command line or parameters
        var cmdLine = cscTask.FindChildrenRecursive<Property>()
            .Where(p => p.Name == "CommandLineArguments" || p.Name == "Sources" || p.Name == "References")
            .ToList();
