        // Look for source file inputs
        var sourceItems = cscTask.FindChildrenRecursive<Item>()
            .Where(i => i.Text.EndsWith(".cs"))
            .ToList();
        Console.WriteLine($"\n  Source files:");
        foreach (var s in sourceItems)
            Console.WriteLine($"    {s.Text}");
        break;
    }
}
