Console.WriteLine("=== ALL REFERENCES PASSED TO CSC FOR SERVICES ===");
foreach (var svc in svcProjects)
{
    var cscTask = svc.FindChildrenRecursive<Task>().FirstOrDefault(t => t.Name == "Csc");
    if (cscTask != null)
    {
        var folder = cscTask.FindChildrenRecursive<Folder>().FirstOrDefault(f => f.Name == "Parameters");
        if (folder != null)
        {
            var refs = folder.FindChildrenRecursive<Item>().Where(i => i.Text.Contains(".dll")).ToList();
            Console.WriteLine($"  Total reference DLLs: {refs.Count}");
            // None are Newtonsoft? Let's confirm
            var newtonsoftRefs = refs.Where(r => r.Text.Contains("Newtonsoft", StringComparison.OrdinalIgnoreCase)).ToList();
            Console.WriteLine($"  Newtonsoft refs: {newtonsoftRefs.Count}");
            if (newtonsoftRefs.Any())
                foreach (var r in newtonsoftRefs) Console.WriteLine($"    {r.Text}");
        }
        break;
    }
}
Console.WriteLine();

// Let's see what the csproj file dependencies look like from NuGet restore
Console.WriteLine("=== RESTORE: PACKAGE SPEC FOR SERVICES ===");
var restoreTask = build.FindChildrenRecursive<Task>().FirstOrDefault(t => t.Name == "RestoreTask");
if (restoreTask != null)
{
    var msgs = restoreTask.FindChildrenRecursive<Message>()
        .Where(m => m.Text != null && m.Text.Contains("Services"))
        .Take(5).ToList();
    foreach (var m in msgs)
        Console.WriteLine($"  {m.Text}");
}

// Let's also look at the project.assets.json path and content hints
