Console.WriteLine("=== PACKAGE RESOLUTION FROM RESTORE ===");
var restoreMsgs = build.FindChildrenRecursive<Message>()
    .Where(m => m.Text != null && m.Text.Contains("Restored") && m.Text.Contains("Services"))
    .ToList();
