using Microsoft.Build.Logging.StructuredLogger;
using System;
using System.Collections.Generic;
using System.Linq;

var binlogPath = "/tmp/sv-9f81bdcebf9d4e5a99861f2ee443bb8b/build.binlog";
var build = BinaryLog.ReadBuild(binlogPath);

// Check if Api.csproj has its own errors (not cascading from Services)
Console.WriteLine("=== ERRORS BY PROJECT ===");
var errors = build.FindChildrenRecursive<Error>().ToList();
var errorsByProj = errors.GroupBy(e => e.GetNearestParent<Project>()?.Name ?? "unknown");
foreach (var g in errorsByProj)
{
    Console.WriteLine($"\n  Project: {g.Key}");
    foreach (var e in g)
        Console.WriteLine($"    [{e.Code}] {e.File}({e.LineNumber},{e.ColumnNumber}): {e.Text}");
}

// Check project dependency chain
Console.WriteLine("\n\n=== PROJECT DEPENDENCY CHAIN ===");
var projRefItems = build.FindChildrenRecursive<AddItem>()
    .Where(a => a.Name == "ProjectReference")
    .ToList();
var seen = new HashSet<string>();
foreach (var addItem in projRefItems)
{
    var proj = addItem.GetNearestParent<Project>();
    foreach (var child in addItem.Children.OfType<Item>())
    {
        var key = $"{proj?.Name} -> {child.Text}";
        if (seen.Add(key))
            Console.WriteLine($"  {key}");
    }
}

// Check if Api had a Csc task (did it even get to compile?)
Console.WriteLine("\n\n=== DID Api.csproj REACH COMPILATION? ===");
var apiProjects = build.FindChildrenRecursive<Project>()
    .Where(p => p.Name == "Api.csproj")
    .ToList();
foreach (var api in apiProjects)
{
    var cscTask = api.FindChildrenRecursive<Task>().FirstOrDefault(t => t.Name == "Csc");
    if (cscTask != null)
        Console.WriteLine($"  YES - Api.csproj (id={api.Id}) ran Csc");
    else
    {
        // Check if it has a Build target that failed
        var buildTarget = api.FindChildrenRecursive<Target>().FirstOrDefault(t => t.Name == "Build" && !t.Succeeded);
        if (buildTarget != null)
            Console.WriteLine($"  NO - Api.csproj (id={api.Id}) Build target failed before Csc");
    }
}

// Check the source files included for services
Console.WriteLine("\n\n=== CSC COMMAND LINE SNIPPET FOR SERVICES (references section) ===");
var svcProjects = build.FindChildrenRecursive<Project>()
    .Where(p => p.Name == "Services.csproj")
    .ToList();
foreach (var svc in svcProjects)
{
    var cscTask = svc.FindChildrenRecursive<Task>().FirstOrDefault(t => t.Name == "Csc");
    if (cscTask != null)
    {
        var cmdLine = cscTask.FindChildrenRecursive<Property>()
            .FirstOrDefault(p => p.Name == "CommandLineArguments");
        if (cmdLine != null)
        {
            // Check if any reference to Newtonsoft exists
            var hasNewtonsoft = cmdLine.Value?.Contains("Newtonsoft", StringComparison.OrdinalIgnoreCase) ?? false;
            Console.WriteLine($"  Newtonsoft in command line: {hasNewtonsoft}");

            // Show the /reference: lines
            var lines = cmdLine.Value?.Split(' ') ?? Array.Empty<string>();
            var refLines = lines.Where(l => l.StartsWith("/reference:")).ToList();
            Console.WriteLine($"  Total /reference: entries: {refLines.Count}");
            var newtonsoftRef = refLines.Where(l => l.Contains("Newtonsoft", StringComparison.OrdinalIgnoreCase)).ToList();
            Console.WriteLine($"  Newtonsoft /reference: entries: {newtonsoftRef.Count}");
        }
        break;
    }
}
EOF

