            var lines = cmdLine.Value?.Split(' ') ?? Array.Empty<string>();
            var refLines = lines.Where(l => l.StartsWith("/reference:")).ToList();
            Console.WriteLine($"  Total /reference: entries: {refLines.Count}");
            var newtonsoftRef = refLines.Where(l => l.Contains("Newtonsoft", StringComparison.OrdinalIgnoreCase)).ToList();
            Console.WriteLine($"  Newtonsoft /reference: entries: {newtonsoftRef.Count}");
        }
        break;
    }
}
